import pytest

def test_reset_token_transitions_from_valid_to_used_state(
    api_client,           # <fixture> authenticated API helper
    valid_reset_token,    # <fixture> issues token < 29 min old
):
    payload = {"token": valid_reset_token, "password": "ValidP@ssw0rd!"}

    # First use: ISSUED -> USED
    first = api_client.post("/api/password/reset", json=payload)
    assert first.status_code == 200, (
        f"First reset must succeed, got {first.status_code}"
    )

    # Second use: USED -> rejected
    second = api_client.post("/api/password/reset", json=payload)
    assert second.status_code == 410, (
        f"Replayed token must be rejected with 410, got {second.status_code}"
    )
